namespace LimbusRuntimeUIInspector.Server;internal static class InspectorPage {     public const string Html = """ <!doctype html> <html lang="en"> <head> <meta charset="utf-8"> <meta name="viewport" content="width=device-width, initial-scale=1"> <title>Limbus Runtime UI Inspector</title> <style> :root{color-scheme:dark;--bg:#15171a;--panel:#20242a;--panel2:#272c33;--line:#3a424d;--text:#eef2f6;--muted:#9aa8b7;--accent:#46b3a2;--danger:#d46a6a} *{box-sizing:border-box}body{margin:0;background:var(--bg);color:var(--text);font:13px/1.4 "Segoe UI",Arial,sans-serif} header{height:52px;display:flex;align-items:center;gap:12px;padding:0 16px;border-bottom:1px solid var(--line);background:#111316} h1{font-size:16px;margin:0;font-weight:650}button,input,label{font:inherit}button{height:30px;border:1px solid var(--line);background:var(--panel2);color:var(--text);border-radius:5px;padding:0 10px;cursor:pointer}button:hover{border-color:var(--accent)}button.primary{background:var(--accent);border-color:var(--accent);color:#07110f}button.danger{border-color:var(--danger);color:#ffdada} input{height:30px;border:1px solid var(--line);background:#111316;color:var(--text);border-radius:5px;padding:0 8px;min-width:0} main{display:grid;grid-template-columns:minmax(360px,1fr) 360px;height:calc(100vh - 52px)} .left,.right{min-height:0}.left{display:flex;flex-direction:column}.toolbar{display:flex;gap:8px;align-items:center;padding:10px;border-bottom:1px solid var(--line);background:var(--panel)} .toolbar input[type=text]{flex:1}.tablewrap{overflow:auto;min-height:0}table{width:100%;border-collapse:collapse;table-layout:fixed}th,td{padding:7px 8px;border-bottom:1px solid #2c333b;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;text-align:left}th{position:sticky;top:0;background:#1b1f24;color:var(--muted);z-index:1}tr{cursor:pointer}tr:hover, tr.selected{background:#263038} .right{border-left:1px solid var(--line);background:var(--panel);padding:12px;overflow:auto}.muted{color:var(--muted)}.path{font-family:Consolas,monospace;word-break:break-all;white-space:normal;background:#15191d;border:1px solid var(--line);padding:8px;border-radius:5px;margin:8px 0 12px} .grid{display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:10px}.grid.three{grid-template-columns:1fr 1fr 1fr}.field span{display:block;color:var(--muted);font-size:11px;margin-bottom:3px}.field input{width:100%}.actions{display:flex;gap:8px;align-items:center;margin:12px 0}.status{color:var(--muted);padding-left:6px}.empty{padding:24px;color:var(--muted)} </style> </head> <body> <header><h1>Limbus Runtime UI Inspector</h1><span class="muted">Local runtime Transform editor</span></header> <main> <section class="left"> <div class="toolbar"> <input id="filter" type="text" placeholder="Filter by name or hierarchy path"> <label><input id="inactive" type="checkbox"> include inactive</label> <label><input id="transforms" type="checkbox" checked> transforms</label> <input id="limit" type="number" min="1" max="20000" step="500" value="5000" title="Maximum returned rows" style="width:82px"> <button id="refresh" class="primary">Refresh</button> </div> <div class="tablewrap"><table><thead><tr><th style="width:80px">ID</th><th style="width:120px">Type</th><th style="width:210px">Name</th><th>Path</th><th style="width:70px">Active</th></tr></thead><tbody id="rows"></tbody></table></div> </section> <aside class="right"> <div id="empty" class="empty">Select an element to edit it.</div> <div id="editor" hidden> <h2 id="title" style="font-size:15px;margin:0"></h2> <div id="path" class="path"></div> <label><input id="active" type="checkbox"> active self</label> <h3 id="posTitle">Position</h3> <div class="grid"><label class="field"><span>X</span><input id="anchoredX" type="number" step="0.1"></label><label class="field"><span>Y</span><input id="anchoredY" type="number" step="0.1"></label></div> <div id="rectOnly"> <h3>Size Delta</h3> <div class="grid"><label class="field"><span>Width</span><input id="width" type="number" step="0.1"></label><label class="field"><span>Height</span><input id="height" type="number" step="0.1"></label></div> <h3>Anchors</h3> <div class="grid"><label class="field"><span>Min X</span><input id="anchorMinX" type="number" step="0.01"></label><label class="field"><span>Min Y</span><input id="anchorMinY" type="number" step="0.01"></label><label class="field"><span>Max X</span><input id="anchorMaxX" type="number" step="0.01"></label><label class="field"><span>Max Y</span><input id="anchorMaxY" type="number" step="0.01"></label></div> <h3>Pivot</h3> <div class="grid"><label class="field"><span>X</span><input id="pivotX" type="number" step="0.01"></label><label class="field"><span>Y</span><input id="pivotY" type="number" step="0.01"></label></div> </div> <h3>Local Scale</h3> <div class="grid three"><label class="field"><span>X</span><input id="scaleX" type="number" step="0.01"></label><label class="field"><span>Y</span><input id="scaleY" type="number" step="0.01"></label><label class="field"><span>Z</span><input id="scaleZ" type="number" step="0.01"></label></div> <div class="actions"><button id="apply" class="primary">Apply</button><button id="hide" class="danger">Hide</button><span id="status" class="status"></span></div> </div> </aside> </main> <script> let selected=null, rows=[]; const $=id=>document.getElementById(id); const fields=["anchoredX","anchoredY","width","height","anchorMinX","anchorMinY","anchorMaxX","anchorMaxY","pivotX","pivotY","scaleX","scaleY","scaleZ"]; async function api(path, opts){const r=await fetch(path, opts); const j=await r.json(); if(!j.ok) throw new Error(j.error||"request failed"); return j.data;} function setStatus(s){$("status").textContent=s||""} function fill(e){selected=e;$("empty").hidden=true;$("editor").hidden=false;$("title").textContent=`${e.name} (${e.id})`;$("path").textContent=e.path;$("active").checked=e.activeSelf;$("posTitle").textContent=e.kind==="RectTransform"?"Anchored Position":"Local Position";$("rectOnly").hidden=e.kind!=="RectTransform";for(const f of fields)$(`${f}`).value=e[f]??"";document.querySelectorAll("tr").forEach(tr=>tr.classList.toggle("selected",Number(tr.dataset.id)===e.id));} function render(){const tbody=$("rows");tbody.innerHTML="";for(const e of rows){const tr=document.createElement("tr");tr.dataset.id=e.id;tr.innerHTML=`<td>${e.id}</td><td>${esc(e.kind||"")}</td><td title="${esc(e.name)}">${esc(e.name)}</td><td title="${esc(e.path)}">${esc(e.path)}</td><td>${e.activeInHierarchy?"yes":"no"}</td>`;tr.onclick=()=>fill(e);tbody.appendChild(tr);}} function replaceRow(e){const i=rows.findIndex(x=>x.id===e.id);if(i>=0)rows[i]=e;else rows.unshift(e);render();fill(e);} function esc(s){return String(s).replace(/[&<>"']/g,c=>({"&":"&amp;","<":"&lt;",">":"&gt;","\"":"&quot;","'":"&#39;"}[c]));} async function waitJob(job, label){let current=job;while(current.state==="pending"||current.state==="running"){setStatus(`${label} ${current.state} (${current.elapsedMs}ms)`);await new Promise(r=>setTimeout(r,250));current=await api(`/api/job?id=${current.jobId}`);}if(current.state!=="complete")throw new Error(current.error||`${label} failed`);return current;} async function refresh(){setStatus("queueing scan");const q=new URLSearchParams({filter:$("filter").value||"",includeInactive:$("inactive").checked?"1":"0",includeTransforms:$("transforms").checked?"1":"0",maxResults:$("limit").value||"5000"});const job=await api(`/api/scan?${q}`);const done=await waitJob(job,"scan");rows=done.result?.elements||[];render();setStatus(`${rows.length} elements`);if(selected){const next=rows.find(x=>x.id===selected.id);if(next)fill(next);}} async function apply(activeOverride){if(!selected)return;const body={id:selected.id};body.active=activeOverride===undefined?$("active").checked:activeOverride;for(const f of fields){const v=$(`${f}`).value;if(v!=="")body[f]=Number(v);}setStatus("queueing edit");const job=await api("/api/edit",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(body)});const done=await waitJob(job,"edit");if(done.element){selected=done.element;replaceRow(done.element);}setStatus("applied");} $("refresh").onclick=()=>refresh().catch(e=>setStatus(e.message));$("apply").onclick=()=>apply().catch(e=>setStatus(e.message));$("hide").onclick=()=>apply(false).catch(e=>setStatus(e.message));$("filter").onkeydown=e=>{if(e.key==="Enter")refresh().catch(err=>setStatus(err.message));};setStatus("ready"); </script> </body> </html> """; }
